const { top_gainers, top_losers } = $input.first().json;

const fmt = (n) =>
  n >= 1e6 ? `$${(n / 1e6).toFixed(2)}M` :
  n >= 1e3 ? `$${(n / 1e3).toFixed(2)}K` : `$${n.toFixed(4)}`;

const clean = (coin) => ({
  name: `${coin.name} (${coin.symbol.toUpperCase()})`,
  price_usd: coin.usd,
  volume_24h: fmt(coin.usd_24h_vol),
  change_24h_pct: `${coin.usd_24h_change > 0 ? "+" : ""}${coin.usd_24h_change.toFixed(2)}%`,
  rank: coin.market_cap_rank ?? "unranked",
});

return [{
  json: {
    top_gainers: top_gainers.map(clean),
    top_losers: top_losers.map(clean),
  }
}];

const d = $input.first().json.data;

const fmt = (n) =>
  n >= 1e12 ? `$${(n / 1e12).toFixed(2)}T` :
  n >= 1e9  ? `$${(n / 1e9).toFixed(2)}B` :
  n >= 1e6  ? `$${(n / 1e6).toFixed(2)}M` : `$${n.toFixed(2)}`;

const mcChange = d.market_cap_change_percentage_24h_usd;
const volChange = d.volume_change_percentage_24h_usd;

return [{
  json: {
    overview: {
      active_cryptocurrencies: d.active_cryptocurrencies,
      markets: d.markets,
      updated_at: new Date(d.updated_at * 1000).toISOString(),
    },
    market_cap: {
      usd: fmt(d.total_market_cap.usd),
      btc_equivalent: `${(d.total_market_cap.btc / 1e6).toFixed(2)}M BTC`,
      change_24h_pct: `${mcChange > 0 ? "+" : ""}${mcChange.toFixed(2)}%`,
    },
    volume_24h: {
      usd: fmt(d.total_volume.usd),
      change_24h_pct: `${volChange > 0 ? "+" : ""}${volChange.toFixed(2)}%`,
    },
    dominance: Object.fromEntries(
      Object.entries(d.market_cap_percentage).map(([k, v]) => [k, `${v.toFixed(2)}%`])
    ),
    sentiment_hint: (() => {
      if (mcChange > 1 && volChange > 10) return "strong bullish — price and volume rising";
      if (mcChange > 0 && volChange < -15) return "weak bullish — price up but volume declining";
      if (mcChange < -1 && volChange > 10) return "strong bearish — price and volume falling hard";
      if (mcChange < 0 && volChange < 0) return "bearish — price and volume both declining";
      return "neutral / consolidating";
    })(),
  }
}];

const d = $input.first().json.data;

const fmt = (n) => {
  const num = parseFloat(n);
  return num >= 1e9 ? `$${(num / 1e9).toFixed(2)}B` :
         num >= 1e6 ? `$${(num / 1e6).toFixed(2)}M` : `$${num.toFixed(2)}`;
};

return [{
  json: {
    defi_market_cap: fmt(d.defi_market_cap),
    eth_market_cap: fmt(d.eth_market_cap),
    defi_to_eth_ratio: `${parseFloat(d.defi_to_eth_ratio).toFixed(2)}%`,
    volume_24h: fmt(d.trading_volume_24h),
    defi_dominance: `${parseFloat(d.defi_dominance).toFixed(2)}%`,
    top_coin: {
      name: d.top_coin_name,
      defi_dominance: `${d.top_coin_defi_dominance.toFixed(2)}%`,
    },
  }
}];

const { coins, nfts, categories } = $input.first().json;

const pct = (n) => `${parseFloat(n) > 0 ? "+" : ""}${parseFloat(n).toFixed(2)}%`;
const fmt = (s) => {
  const n = parseFloat(s.replace(/[$,]/g, ""));
  return n >= 1e9 ? `$${(n / 1e9).toFixed(2)}B` :
         n >= 1e6 ? `$${(n / 1e6).toFixed(2)}M` :
         n >= 1e3 ? `$${(n / 1e3).toFixed(2)}K` : `$${n.toFixed(4)}`;
};

return [{
  json: {
    trending_coins: coins.map(({ item }) => ({
      name: `${item.name} (${item.symbol.toUpperCase()})`,
      rank: item.market_cap_rank ?? "unranked",
      price_usd: `$${item.data.price < 0.01 ? item.data.price.toFixed(6) : item.data.price.toFixed(4)}`,
      change_24h: pct(item.data.price_change_percentage_24h.usd),
      market_cap: fmt(item.data.market_cap),
      volume_24h: fmt(item.data.total_volume),
      about: item.data.content?.description ?? null,
    })),

    trending_nfts: nfts.map((nft) => ({
      name: `${nft.name} (${nft.symbol})`,
      floor_price: nft.data.floor_price,
      floor_change_24h: pct(nft.floor_price_24h_percentage_change),
      volume_24h: nft.data.h24_volume,
      avg_sale_price: nft.data.h24_average_sale_price,
    })),

    trending_categories: categories.map((cat) => ({
      name: cat.name,
      coins: cat.coins_count,
      market_cap: fmt(cat.data.market_cap.toString()),
      change_24h: pct(cat.data.market_cap_change_percentage_24h.usd),
      volume_24h: fmt(cat.data.total_volume.toString()),
    })),
  }
}];

const raw = $input.first().json;
const nfts = Array.isArray(raw) ? raw : $input.all().map(i => i.json);

const pct = (n) => n == null ? null : `${n > 0 ? "+" : ""}${parseFloat(n).toFixed(2)}%`;
const fmtUsd = (n) => {
  if (!n) return "$0";
  return n >= 1e6 ? `$${(n / 1e6).toFixed(2)}M`
       : n >= 1e3 ? `$${(n / 1e3).toFixed(2)}K`
       : `$${n.toFixed(2)}`;
};
const stripHtml = (s) => s
  ? s.replace(/<[^>]*>/g, "").replace(/\s+/g, " ").trim().slice(0, 300)
  : null;

return [{
  json: {
    collections: nfts.map((nft) => ({
      name: `${nft.name} (${nft.symbol})`,
      contract: nft.contract_address,
      blockchain: nft.asset_platform_id,
      description: stripHtml(nft.description),
      floor_price: {
        native: `${nft.floor_price?.native_currency?.toFixed(4) ?? "N/A"} ${nft.native_currency_symbol ?? ""}`,
        usd: fmtUsd(nft.floor_price?.usd),
      },
      market_cap_usd: fmtUsd(nft.market_cap?.usd),
      volume_24h: {
        native: `${nft.volume_24h?.native_currency?.toFixed(2) ?? "N/A"} ${nft.native_currency_symbol ?? ""}`,
        usd: fmtUsd(nft.volume_24h?.usd),
      },
      floor_change_24h: pct(nft.floor_price_in_usd_24h_percentage_change),
      owners: nft.number_of_unique_addresses,
      total_supply: nft.total_supply,
    }))
  }
}];

const allItems = $input.all();

return [
  {
    json: {
      marketData: allItems.map((item, index) => ({
        source: `api_${index + 1}`,
        data: item.json,
      })),
    },
  },
];

const markdown = $json.output;

const html = markdown
  .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
  .replace(/^---$/gm, '<hr>')
  .replace(/\n/g, '<br>');

return [
  {
    json: {
      html
    }
  }
];
